+fn extract_rowid_range_bound<'a>(
+    left: &'a Expr,
+    op: fsqlite_ast::BinaryOp,
+    right: &'a Expr,
+    table: Option<&TableSchema>,
+    table_alias: Option<&str>,
+) -> Option<(RowidRangeSlot, RowidRangeBound<'a>)> {
+    if is_rowid_expr(left, table, table_alias) && is_rowid_range_constant(right) {
+        return match op {
+            fsqlite_ast::BinaryOp::Ge => Some((
+                RowidRangeSlot::Lower,
+                RowidRangeBound {
+                    rowid_expr: left,
+                    expr: right,
+                    inclusive: true,
+                },
+            )),
+            fsqlite_ast::BinaryOp::Gt => Some((
+                RowidRangeSlot::Lower,
+                RowidRangeBound {
+                    rowid_expr: left,
+                    expr: right,
+                    inclusive: false,
+                },
+            )),
+            fsqlite_ast::BinaryOp::Le => Some((
+                RowidRangeSlot::Upper,
+                RowidRangeBound {
+                    rowid_expr: left,
+                    expr: right,
+                    inclusive: true,
+                },
+            )),
+            fsqlite_ast::BinaryOp::Lt => Some((
+                RowidRangeSlot::Upper,
+                RowidRangeBound {
+                    rowid_expr: left,
+                    expr: right,
+                    inclusive: false,
+                },
+            )),
+            _ => None,
+        };
+    }
+
+    if is_rowid_expr(right, table, table_alias) && is_rowid_range_constant(left) {
+        return match op {
+            fsqlite_ast::BinaryOp::Le => Some((
+                RowidRangeSlot::Lower,
+                RowidRangeBound {
+                    rowid_expr: right,
+                    expr: left,
+                    inclusive: true,
+                },
+            )),
+            fsqlite_ast::BinaryOp::Lt => Some((
+                RowidRangeSlot::Lower,
+                RowidRangeBound {
+                    rowid_expr: right,
+                    expr: left,
+                    inclusive: false,
+                },
+            )),
+            fsqlite_ast::BinaryOp::Ge => Some((
+                RowidRangeSlot::Upper,
+                RowidRangeBound {
+                    rowid_expr: right,
+                    expr: left,
+                    inclusive: true,
+                },
+            )),
+            fsqlite_ast::BinaryOp::Gt => Some((
+                RowidRangeSlot::Upper,
+                RowidRangeBound {
+                    rowid_expr: right,
+                    expr: left,
+                    inclusive: false,
+                },
+            )),
+            _ => None,
+        };
+    }
+
+    None
+}
